CREATE TABLE cost_subject_legacy_cleanup_audit (
    id BIGINT NOT NULL PRIMARY KEY,
    tenant_id BIGINT NOT NULL DEFAULT 0,
    legacy_subject_id BIGINT NOT NULL,
    legacy_subject_code VARCHAR(64) NOT NULL,
    legacy_subject_name VARCHAR(200) NOT NULL,
    replacement_subject_id BIGINT NOT NULL,
    replacement_subject_code VARCHAR(64) NOT NULL,
    replacement_subject_name VARCHAR(200) NOT NULL,
    migration_reason VARCHAR(500) NOT NULL,
    migrated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT uk_legacy_cost_subject_cleanup UNIQUE (tenant_id, legacy_subject_id)
);

